(79,12,'Database Integration in Desktop Apps','## Connecting Desktop Apps to SQLite

SQLite is a lightweight, file-based database perfect for desktop applications. No server required — the entire database is a single file.

## Python sqlite3 Module

```python
import sqlite3
from contextlib import contextmanager

DB_PATH = ''students.db''

def init_db():
    with sqlite3.connect(DB_PATH) as conn:
        conn.execute(''''''
            CREATE TABLE IF NOT EXISTS students (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                email TEXT UNIQUE NOT NULL,
                course TEXT,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        '''''')
        conn.commit()

def add_student(name: str, email: str, course: str) -> int:
    with sqlite3.connect(DB_PATH) as conn:
        cursor = conn.execute(
            ''INSERT INTO students (name, email, course) VALUES (?,?,?)'',
            (name, email, course)
        )
        conn.commit()
        return cursor.lastrowid

def get_all_students() -> list:
    with sqlite3.connect(DB_PATH) as conn:
        conn.row_factory = sqlite3.Row
        return conn.execute(''SELECT * FROM students ORDER BY name'').fetchall()

def search_students(query: str) -> list:
    with sqlite3.connect(DB_PATH) as conn:
        conn.row_factory = sqlite3.Row
        return conn.execute(
            ''SELECT * FROM students WHERE name LIKE ? OR email LIKE ?'',
            (f''%{query}%'', f''%{query}%'')
        ).fetchall()

def delete_student(student_id: int) -> None:
    with sqlite3.connect(DB_PATH) as conn:
        conn.execute(''DELETE FROM students WHERE id = ?'', (student_id,))
        conn.commit()
```

## Integrating with PyQt5

```python
def load_students(self):
    students = get_all_students()
    self.table.setRowCount(0)
    for student in students:
        row = self.table.rowCount()
        self.table.insertRow(row)
        self.table.setItem(row, 0, QTableWidgetItem(str(student[''id''])))
        self.table.setItem(row, 1, QTableWidgetItem(student[''name'']))
        self.table.setItem(row, 2, QTableWidgetItem(student[''email'']))
```

